import { useState, useEffect } from "react";

const MY_EMAIL = "balani.emmanuel99@gmail.com"; // 👈 CHANGE THIS

const CHILDHOOD_PHOTO = "";

const HEADER = '"Jojowain o Totropahin" Compatibility Check (Speed lang hehe)';

const BOOT = [
  "Kalokohan ni Emmanuel initializing...",
  "Loading cute personality modules... ✓",
  "Calibrating cuteness ko algorithms... ✓",
  "Potential jowa o tropa detected: Miss Madam Carelle Miles ✓",
  "Checking kung kumakausap ka ba ng baliw",
  "⚠ Warning: Abnormal talaga gumawa neto jusq",
  "G na? Ako ready na..",
];

const SAD_COMMENTS = [
  "...",
  "hoyyy...",
  "jusq po rudy...",
  "ok. edi don't",
  "sad boi na ako hanep ka",
  "ok, ok. salamat sa lahat. bye.",
];

const QUESTIONS = [
  {
    sys: "Scanning primary hobby data...",
    q: "Hobby neto ay matulog ng matulog ng matulog. Wala kang ibang kaagaw bukod sa tulog. Your thoughts?",
    options: [
      "Goods lang basta ako ang laman ng panaginip.",
      "Very good yan para healthy.",
      "As long as hindi nangchi-chix, walang problema.",
      "Cutie naman siya ehh kaya tanggap ko.. ",
    ],
    reveal: "⚡ Perfect — Pwede ka sigurong tumabi sa pagtulog.. (Kaya lang, malakas to humarok FYI)",
  },
  {
    sys: "Analyzing conversational patterns...",
    q: "Malala ka-chat to. Minsan mukhang professional, minsan mukhang mature, may times na parang ang seryoso pero nako madalas dogshow tong punyeta na to. Your thoughts?:",
    options: [
      "Arf! Arf! Arf!",
      "Okay lang kasi yung friend ko na si Jean eh mukhang shitzu.",
      "Block ko to agad!",
      "Let's see once na magka-chat na kami.",
    ],
    reveal: "⚠ CONFIRMED — May lahing shitzu talaga si Jean. Ay Maliii!! I mean, let's see how it goes..",
  },
  {
    sys: "Processing response time data...",
    q: "Maraming beses na siyang nakalimot magreply sa chat, kahit sa mga family members niya. Tanggap parin naman siya ng pamilya niya kasi daw cute naman.. How about you?",
    options: [
      "Accept din kasi nga cute naman talaga.",
      "Bye. Salamat nalang sa lahat.",
      "Kung part ako ng family neto, ipapa-ampon ko sa malayo.",
      "Tingnan nga natin kung makalimot parin magreply kapag ako ang ka-chat.. ",
    ],
    reveal: "📋 LEGIT — Sadyang very low maintenance talaga. Clingy naman to siya pero malamang tulog nanaman kaya no reply.",
  },
  {
    sys: "Running physical and talent metrics...",
    q: "Height: 5'9\". Weight: Sobrang Mabigat haha. Special skill: Kumanta ng Arthur Nery songs kahit kaboses ni Willie Revillame sa videoke. Kaya pa?",
    options: [
      "The confidence is lowkey kind of attractive.",
      "5'9\" works. The Arthur Nery part — I need a live sample.",
      "I respect the commitment to the bit.",
      "Height approved. The singing is a bonus I didn't ask for.",
    ],
    reveal: "🎵 NOTED — He is trying to be humble, he really does sound like Arthur Nery. Both of them are also yummy (hehe)",
  },
  {
    sys: "Loading intention module...",
    q: "He's not out here chasing anyone. But if he ever actually decides to go for someone — it's always real, it's intentional, and it's because he sees a future there. How does that land?",
    options: [
      "That's genuinely rare to hear. I'm listening.",
      "Chill but intentional? Okay, I'm paying attention now.",
      "No games, no situationships — I can respect that.",
      "He had me at 'intentional.'",
    ],
    reveal: "💍 CONFIRMED — He goes with the flow, very chill. Simple. But he will never take anyone's feelings for granted, he only dates to marry. (Mindset ba midset) ",
  },
];

export default function CompatibilityCheck() {
  const [phase, setPhase] = useState("boot");
  const [bootStep, setBootStep] = useState(0);
  const [nameInput, setNameInput] = useState("");
  const [nickname, setNickname] = useState("Carelle");
  const [currentQ, setCurrentQ] = useState(0);
  const [answers, setAnswers] = useState([]);
  const [revealed, setRevealed] = useState(false); // has this question been answered/revealed
  const [noCount, setNoCount] = useState(0);
  const [noPos, setNoPos] = useState(null);
  const [done, setDone] = useState(false);

  useEffect(() => {
    if (phase !== "boot") return;
    if (bootStep >= BOOT.length) {
      setTimeout(() => setPhase("name"), 900);
      return;
    }
    const t = setTimeout(() => setBootStep((s) => s + 1), 430);
    return () => clearTimeout(t);
  }, [phase, bootStep]);

  const submitName = () => {
    const n = nameInput.trim();
    if (!n) return;
    setNickname(n);
    setPhase("quiz");
  };

  const pickAnswer = (idx) => {
    setAnswers((prev) => {
      const copy = [...prev];
      copy[currentQ] = idx;
      return copy;
    });
    setRevealed(true);
  };

  const nextQuestion = () => {
    if (currentQ + 1 < QUESTIONS.length) {
      setCurrentQ((q) => q + 1);
      setRevealed(false);
    } else {
      setPhase("results");
    }
  };

  const goBack = () => {
    if (currentQ === 0) {
      setPhase("name");
      return;
    }
    setCurrentQ((q) => q - 1);
    setRevealed(true); // previous question was already answered
  };

  const clickNo = () => {
    if (noCount < 5) {
      setNoPos({
        top: `${10 + Math.random() * 52}%`,
        left: `${4 + Math.random() * 44}%`,
      });
      setNoCount((c) => c + 1);
    } else {
      triggerEmail(`NO (after ${noCount + 1} attempts — make of that what you will)`);
    }
  };

  const clickYes = () => triggerEmail("YES ✓");

  const triggerEmail = (answer) => {
    const sub = encodeURIComponent("Compatibility Check — Final Answer");
    const bod = encodeURIComponent(
      `Hey Emmanuel,\n\n${nickname} has completed the potential compatibility check.\n\nFinal answer: ${answer}\n\nYou're welcome. The rest is up to you.\n\n— CompatibilityOS v2.1.4`
    );
    window.open(`mailto:${MY_EMAIL}?subject=${sub}&body=${bod}`, "_blank");
    setDone(true);
  };

  const G = {
    bg: "#0d0d0d", card: "#111", border: "#1f1f1f",
    green: "#40c798", purple: "#7b51bf", white: "#f0f0f0",
    dim: "#555", muted: "#888",
  };

  const wrap = {
    minHeight: "100vh", background: G.bg, display: "flex",
    alignItems: "center", justifyContent: "center",
    fontFamily: "'Courier New', monospace", padding: 20,
    boxSizing: "border-box", position: "relative",
  };

  const card = {
    maxWidth: 560, width: "100%", background: G.card,
    border: `1px solid ${G.border}`, borderRadius: 8,
    padding: "26px 30px", boxSizing: "border-box",
  };

  const label = { color: G.purple, fontSize: 10, letterSpacing: "0.15em", marginBottom: 6 };

  const mkBtn = (bg, color, extra = {}) => ({
    fontFamily: "monospace", cursor: "pointer", border: "none",
    borderRadius: 4, padding: "12px 20px", fontSize: 13,
    background: bg, color, ...extra,
  });

  // Persistent quiz header
  const QuizHeader = () => (
    <div style={{
      borderBottom: `1px solid ${G.border}`, paddingBottom: 14, marginBottom: 18,
      textAlign: "center",
    }}>
      <div style={{ color: G.green, fontSize: 13, fontWeight: "bold", lineHeight: 1.5 }}>
        {HEADER}
      </div>
    </div>
  );

  // ===== PHASES =====

  if (phase === "boot") return (
    <div style={wrap}>
      <div style={card}>
        <div style={label}>POTENTIAL COMPATIBILITY DIAGNOSTICS — BOOT SEQUENCE</div>
        <div style={{ marginTop: 16 }}>
          {BOOT.slice(0, bootStep).map((line, i) => (
            <div key={i} style={{ fontSize: 12, color: i === bootStep - 1 ? G.white : G.muted, marginBottom: 8, lineHeight: 1.5 }}>
              <span style={{ color: G.green, marginRight: 8 }}>›</span>{line}
            </div>
          ))}
        </div>
        {bootStep >= BOOT.length && <div style={{ color: G.green, marginTop: 10 }}>█</div>}
      </div>
    </div>
  );

  if (phase === "name") return (
    <div style={wrap}>
      <div style={card}>
        <QuizHeader />
        <div style={label}>SUBJECT IDENTIFICATION</div>
        <div style={{ color: G.muted, fontSize: 11, marginBottom: 22 }}>Required before system can proceed.</div>
        <div style={{ color: G.white, fontSize: 14, lineHeight: 1.75, marginBottom: 20 }}>
          <span style={{ color: G.green }}>SYS:</span> Potential match "Carelle Miles" has been detected.
          <br />Before we begin — what should we actually call you?
        </div>
        <input
          autoFocus value={nameInput}
          onChange={(e) => setNameInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && submitName()}
          placeholder="Type your preferred name..."
          style={{
            width: "100%", boxSizing: "border-box", padding: "11px 14px",
            background: "#0a0a0a", border: `1px solid ${G.purple}`, borderRadius: 4,
            color: G.white, fontFamily: "monospace", fontSize: 14, outline: "none", marginBottom: 14,
          }}
        />
        <button onClick={submitName} style={{ ...mkBtn(G.purple, "#fff"), width: "100%" }}>
          CONFIRM AND PROCEED →
        </button>
      </div>
    </div>
  );

  if (phase === "quiz") {
    const q = QUESTIONS[currentQ];
    const selected = answers[currentQ];
    return (
      <div style={wrap}>
        <div style={card}>
          <QuizHeader />

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 6 }}>
            <div style={label}>POTENTIAL COMPATIBILITY SCAN — {nickname.toUpperCase()}</div>
            <div style={{ color: G.dim, fontSize: 10 }}>{currentQ + 1}/{QUESTIONS.length}</div>
          </div>
          <div style={{ height: 2, background: G.border, borderRadius: 1, marginBottom: 20 }}>
            <div style={{ height: 2, background: G.purple, width: `${((currentQ + (revealed ? 1 : 0)) / QUESTIONS.length) * 100}%`, transition: "width 0.4s", borderRadius: 1 }} />
          </div>

          <div style={{ color: G.green, fontSize: 10, letterSpacing: "0.1em", marginBottom: 10 }}>{q.sys}</div>
          <div style={{ color: G.white, fontSize: 14, lineHeight: 1.7, marginBottom: 18 }}>{q.q}</div>

          <div style={{ display: "flex", flexDirection: "column", gap: 9, marginBottom: 16 }}>
            {q.options.map((opt, i) => {
              const isSel = selected === i;
              return (
                <button key={i} onClick={() => pickAnswer(i)}
                  style={{
                    ...mkBtn(isSel ? "#20202e" : "#181818", G.white),
                    textAlign: "left", padding: "11px 14px",
                    border: `1px solid ${isSel ? G.purple : "#2a2a2a"}`,
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.borderColor = G.purple)}
                  onMouseLeave={(e) => (e.currentTarget.style.borderColor = isSel ? G.purple : "#2a2a2a")}
                >
                  <span style={{ color: G.dim, marginRight: 10 }}>{String.fromCharCode(65 + i)}.</span>{opt}
                </button>
              );
            })}
          </div>

          {revealed && (
            <div style={{
              background: "#141414", border: `1px solid ${G.green}25`, borderRadius: 6,
              padding: "16px 18px", marginBottom: 18,
              display: "flex", gap: 14, alignItems: "center",
            }}>
              <img
                src={`data:image/png;base64,${CHILDHOOD_PHOTO}`}
                alt="evidence"
                style={{
                  width: 64, height: 64, objectFit: "cover", borderRadius: 6,
                  border: `1px solid ${G.purple}`, flexShrink: 0,
                }}
              />
              <div>
                <div style={{ color: G.green, fontSize: 9, letterSpacing: "0.1em", marginBottom: 6 }}>ANALYSIS COMPLETE — EXHIBIT {String.fromCharCode(65 + currentQ)}</div>
                <div style={{ color: G.white, fontSize: 12.5, lineHeight: 1.7 }}>{q.reveal}</div>
              </div>
            </div>
          )}

          <div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}>
            <button onClick={goBack}
              style={{ ...mkBtn("transparent", G.dim), border: `1px solid ${G.border}`, fontSize: 11, padding: "9px 16px" }}>
              ← back
            </button>
            <button onClick={nextQuestion} disabled={!revealed}
              style={{
                ...mkBtn(revealed ? G.purple : "#1a1a1a", revealed ? "#fff" : G.dim),
                fontSize: 12, padding: "9px 22px",
                cursor: revealed ? "pointer" : "not-allowed",
                border: revealed ? "none" : `1px solid ${G.border}`,
              }}>
              {currentQ + 1 < QUESTIONS.length ? "next →" : "see results →"}
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (phase === "results") {
    const rows = [
      ["Sleep alignment", "OPTIMAL ✓"],
      ["Chaos tolerance required", "HIGH ✓"],
      ["Response time expectations", "ADJUSTED ✓"],
      ["Vocal confidence (Arthur Nery)", "UNCHECKED ✓"],
      ["Long-term intention", "CONFIRMED ✓"],
    ];
    return (
      <div style={wrap}>
        <div style={card}>
          <QuizHeader />
          <div style={label}>POTENTIAL COMPATIBILITY REPORT — FINAL</div>
          <div style={{ color: G.muted, fontSize: 11, marginBottom: 24 }}>
            Full scan complete. {nickname} × Potential match analysis finalized.
          </div>
          <div style={{ textAlign: "center", marginBottom: 28 }}>
            <div style={{ color: G.green, fontSize: 58, fontWeight: "bold", letterSpacing: -2 }}>98.7%</div>
            <div style={{ color: G.white, fontSize: 15, marginTop: 2 }}>POTENTIAL COMPATIBILITY CONFIRMED</div>
            <div style={{ color: G.dim, fontSize: 10, marginTop: 6 }}>Margin of error: 0.00% — results are final and non-negotiable.</div>
          </div>
          <div style={{ borderTop: `1px solid ${G.border}`, paddingTop: 18, marginBottom: 22 }}>
            {rows.map(([k, v]) => (
              <div key={k} style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
                <span style={{ color: G.muted, fontSize: 12 }}>{k}</span>
                <span style={{ color: G.green, fontSize: 12 }}>{v}</span>
              </div>
            ))}
          </div>
          <div style={{ background: "#151515", border: `1px solid ${G.border}`, borderRadius: 6, padding: "16px 18px", marginBottom: 24 }}>
            <div style={{ color: G.dim, fontSize: 10, letterSpacing: "0.1em", marginBottom: 8 }}>SYSTEM SUMMARY</div>
            <div style={{ color: G.white, fontSize: 13, lineHeight: 1.8 }}>
              {nickname}, the data is clear. Your potential match sleeps unapologetically, sings Arthur Nery with full conviction and optional pitch, replies eventually and means it, and — against all odds — matches the algorithm almost perfectly.
            </div>
          </div>
          <button onClick={() => setPhase("final")} style={{ ...mkBtn(G.purple, "#fff"), width: "100%" }}>
            ONE FINAL QUESTION →
          </button>
        </div>
      </div>
    );
  }

  if (phase === "final") {
    return (
      <div style={wrap}>
        <div style={{ ...card, position: "relative" }}>
          <QuizHeader />
          <div style={label}>CONFIRMATION REQUIRED</div>
          <div style={{ color: G.muted, fontSize: 11, marginBottom: 24 }}>This response will be recorded and transmitted.</div>
          <div style={{ color: G.white, fontSize: 16, lineHeight: 1.7, marginBottom: 6 }}>
            {nickname}, do you agree with the potential compatibility results?
          </div>
          <div style={{ color: G.dim, fontSize: 11, marginBottom: 28 }}>
            Choose carefully. The system is watching.
          </div>

          {done ? (
            <div style={{ textAlign: "center", padding: "20px 0" }}>
              <div style={{ color: G.green, fontSize: 24, marginBottom: 10 }}>✓ RESPONSE LOGGED</div>
              <div style={{ color: G.white, fontSize: 14 }}>He's been notified.</div>
              <div style={{ color: G.dim, fontSize: 12, marginTop: 8 }}>He'll reach out soon. Give him a day. Maybe two.</div>
            </div>
          ) : (
            <>
              <div style={{ position: "relative", height: 160 }}>
                <button
                  onClick={clickYes}
                  style={{
                    ...mkBtn(G.green, "#0d0d0d"),
                    position: "absolute", left: 0, top: "50%", transform: "translateY(-50%)",
                    width: 180, fontWeight: "bold", fontSize: 15,
                  }}
                >
                  YES
                </button>

                <button
                  onClick={clickNo}
                  style={{
                    ...mkBtn("#1a1a1a", G.white),
                    border: "1px solid #333",
                    position: "absolute",
                    width: 180, fontSize: 15,
                    transition: "top 0.12s ease, left 0.12s ease",
                    ...(noPos
                      ? { top: noPos.top, left: noPos.left, right: "auto", transform: "none" }
                      : { right: 0, top: "50%", transform: "translateY(-50%)" }),
                  }}
                >
                  NO{noCount > 0 ? ` (${noCount + 1})` : ""}
                </button>
              </div>

              {noCount > 0 && (
                <div style={{ color: G.muted, fontSize: 11, textAlign: "center", marginTop: 8, fontStyle: "italic" }}>
                  {SAD_COMMENTS[Math.min(noCount, SAD_COMMENTS.length - 1)]}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    );
  }
}
